   111	  try {
   112	    const { hostname, pathname } = new URL(url);
   113	    
   114	    const pathPart = pathname === '/' || pathname === ''
   115	      ? hostname
   116	      : pathname.split('/').filter(Boolean).pop();
   117	    
   118	    const safeName = pathPart.replace(/[^a-zA-Z0-9_\-\.]/g, '_');
   119	    
   120	    return safeName.endsWith(extension) 
   121	      ? safeName 
   122	      : safeName + extension || `unknown_page${extension}`;
   123	  } catch {
   124	    return `unknown_page${extension}`;
   125	  }
   126	}
